class SparseTableGCD:
    function init(arr):
        this.n=arr.length
        this.LOG=array of size(this.n+1),filled with 0
        for i=2 to this.n:
            this.LOG[i]=this.LOG[i / 2]+1

        K=this.LOG[this.n]+1
